    if (msg !== null && msg !== undefined) {
        console.log(msg.trim());
    }
}

examples.toCode:
func display(msg: String?) {
    if let unwrapped = msg {
        print(unwrapped.trimmingCharacters(in: .whitespacesAndNewlines))
    }
}

